import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const Dashboard = () => {
  const [user, setUser] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    const token = localStorage.getItem("token");
    const userData = localStorage.getItem("user");
    if (!token || !userData) {
      navigate("/login");
    } else {
      setUser(JSON.parse(userData));
    }
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    navigate("/login");
  };

  if (!user) return <div className="page-card">Loading...</div>;

  return (
    <div className="page-card">
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          gap: "16px",
          flexWrap: "wrap",
        }}
      >
        <div>
          <h2>Welcome back, {user.firstName}!</h2>
          <p className="status-chip">Role: {user.role}</p>
        </div>
        <button onClick={handleLogout}>Logout</button>
      </div>

      <div className="action-grid">
        {user.role === "RIDER" && (
          <>
            <div className="action-card">
              <h3>Book a Ride</h3>
              <p>Find the best route and request a ride with one click.</p>
              <button
                onClick={() => navigate("/book-ride")}
                className="nav-button"
              >
                Start Booking
              </button>
            </div>
            <div className="action-card">
              <h3>Ride History</h3>
              <p>Review past trips, fares, and completed rides.</p>
              <button
                onClick={() => navigate("/ride-history")}
                className="nav-button"
              >
                View History
              </button>
            </div>
          </>
        )}

        {user.role === "DRIVER" && (
          <>
            <div className="action-card">
              <h3>Available Rides</h3>
              <p>Accept new ride requests and manage active trips.</p>
              <button className="nav-button">View Available Rides</button>
            </div>
            <div className="action-card">
              <h3>Earnings</h3>
              <p>Track earnings and completed ride performance.</p>
              <button className="nav-button">View Earnings</button>
            </div>
          </>
        )}

        {user.role === "ADMIN" && (
          <>
            <div className="action-card">
              <h3>User Management</h3>
              <p>Manage riders, drivers, and system access controls.</p>
              <button className="nav-button">Manage Users</button>
            </div>
            <div className="action-card">
              <h3>Reports</h3>
              <p>View system analytics and platform activity metrics.</p>
              <button className="nav-button">View Reports</button>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default Dashboard;
